ALTER TABLE emission_project_registry ADD COLUMN IF NOT EXISTS reporting_year integer, ADD COLUMN IF NOT EXISTS period_start date, ADD COLUMN IF NOT EXISTS period_end date;
CREATE UNIQUE INDEX IF NOT EXISTS ux_emission_project_registry_name ON emission_project_registry (lower(trim(project_name)));
CREATE TABLE IF NOT EXISTS emission_project_member (project_id varchar(40) NOT NULL REFERENCES emission_project_registry(project_id) ON DELETE CASCADE, member_name varchar(100) NOT NULL, role_code varchar(30) NOT NULL DEFAULT 'OWNER', created_at timestamp NOT NULL DEFAULT current_timestamp, PRIMARY KEY (project_id, member_name, role_code));
CREATE TABLE IF NOT EXISTS emission_project_task (task_id bigserial PRIMARY KEY, project_id varchar(40) NOT NULL REFERENCES emission_project_registry(project_id) ON DELETE CASCADE, task_code varchar(40) NOT NULL, task_name varchar(100) NOT NULL, step_order integer NOT NULL, task_status varchar(20) NOT NULL DEFAULT 'WAITING', progress_weight integer NOT NULL DEFAULT 0, due_date date, created_at timestamp NOT NULL DEFAULT current_timestamp, UNIQUE (project_id, task_code));
CREATE TABLE IF NOT EXISTS emission_project_history (history_id bigserial PRIMARY KEY, project_id varchar(40) NOT NULL REFERENCES emission_project_registry(project_id) ON DELETE CASCADE, event_type varchar(40) NOT NULL, event_description varchar(500) NOT NULL, actor_name varchar(100), created_at timestamp NOT NULL DEFAULT current_timestamp);
